#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        char A[105], B[105];
        scanf("%s %s",A,B);
        int freq[26]={0};
        for(int i=0;A[i];++i) freq[A[i]-'a']++;
        for(int i=0;B[i];++i) freq[B[i]-'a']++;
        int N; scanf("%d",&N);
        int need[26]={0};
        char child[105];
        for(int i=0;i<N;++i){
            scanf("%s",child);
            for(int j=0;child[j];++j) need[child[j]-'a']++;
        }
        int ok=1;
        for(int i=0;i<26;++i) if(need[i]>freq[i]){ ok=0; break; }
        printf(ok?"YES\n":"NO\n");
    }
    return 0;
}

