  const need = Array(26).fill(0);
  for (let i = 0; i < N; ++i) {
    const child = input[idx++];
    for (const ch of child) need[ch.charCodeAt(0) - 97]++;
  }
  let ok = true;
  for (let i = 0; i < 26; ++i) if (need[i] > freq[i]) { ok = false; break; }
  results.push(ok ? 'YES' : 'NO');
}
console.log(results.join('\n'));

